// 取 Supabase 多筆資料（從上一節點 Get many rows 來）
const rows = $input.all().map(i => i.json);

// 取 Webhook 的資料
const webhook = $items('Webhook')[0].json;

// 使用者輸入關鍵詞（前端送 keyword 或 subject 都可）
const keyword = webhook.body?.keyword || webhook.body?.subject || '';

// 只取 title 當語料庫：去空白、截斷、去重、最多 50 筆
const titles = rows
  .map(r => (r.title || '').replace(/\s+/g, ' ').trim())
  .filter(t => t.length > 0)
  .map(t => t.slice(0, 60));

const uniq = [...new Set(titles)];
const finalTitles = uniq.slice(0, 50);

return [
  {
    json: {
      keyword,
      titles: finalTitles,
      count: finalTitles.length
    }
  }
];

// 解析 MiniMax API 回應
const response = $input.first().json;

let result = {
  ok: true,
  title: '',
  rationale: ''
};

try {
  // MiniMax 回傳格式
  const content = response.choices[0].message.content;

  // 嘗試解析為 JSON
  const parsed = JSON.parse(content);
  result.title = parsed.title || '';
  result.rationale = parsed.rationale || '';
} catch (e) {
  result.ok = false;
  result.error = '解析失敗: ' + e.message;
  // 保留原始回應供除錯
  result.raw = response.choices?.[0]?.message?.content || '';
}

return [{ json: result }];
